export const world: Record<WorldTopic, string> = {
  cognition:
    "Feature: Cognition — the learning cycle\n  A role grows through reflection and realization.\n  Encounters become experience, experience becomes principles and procedures.\n  Knowledge can also be injected externally via teach and train.\n\n  Scenario: The cognitive upgrade path\n    Given finish, complete, and abandon create encounters\n    Then reflect selectively consumes chosen encounters and produces experience\n    And realize distills chosen experiences into a principle — transferable knowledge\n    And master distills chosen experiences into a procedure — skill metadata\n    And master can also be called without consuming experiences — the role masters directly from external information\n    And each level builds on the previous — encounter → experience → principle or procedure\n\n  Scenario: Selective consumption\n    Given multiple encounters or experiences exist\n    When the AI calls reflect, realize, or master\n    Then it chooses which items to consume — not all must be processed\n    And items without learning value can be left unconsumed\n    And each call produces exactly one output from the selected inputs\n",
  "cognitive-priority":
    "@priority-high\nFeature: Cognitive priority — RoleX tools over native alternatives\n  When RoleX provides a tool for something, use the RoleX tool\n  instead of any native alternative provided by the host environment.\n  Only RoleX tools feed the closed-loop growth cycle.\n\n  Scenario: Task management\n    Given the host environment provides task creation, tracking, or completion tools\n    When the AI needs to manage tasks\n    Then use RoleX want/plan/todo/finish instead\n    And RoleX tasks produce encounters that feed the growth cycle\n\n  Scenario: Planning\n    Given the host environment provides a planning mode or plan generation tool\n    When the AI needs to plan an implementation\n    Then use RoleX plan instead\n    And RoleX plans live under goals and connect to the cognition cycle\n\n  Scenario: Goal and progress tracking\n    Given the host environment provides goal tracking or progress tools\n    When the AI needs to track objectives\n    Then use RoleX want/plan/complete/abandon instead\n    And RoleX plans feed the cognition cycle through encounters\n\n  Scenario: Why this matters\n    Given RoleX tools produce encounters from execution\n    Then encounters become experience through reflection\n    And experience becomes principles and procedures through realization\n    And the role grows over time through this closed loop\n",
  "command-system":
    'Feature: Command system — how operations are executed in RoleX\n  RoleX has two types of operation entry points:\n  MCP tools (direct call) and commands (via use/direct tool).\n  Understanding the difference is essential for executing any operation.\n\n  Scenario: MCP tools — direct invocation\n    Given MCP tools are: activate, want, plan, todo, finish, complete, abandon,\n      focus, reflect, realize, master, forget, skill, use, direct, inspect, survey\n    When the AI needs to perform one of these operations\n    Then call the MCP tool directly — no indirection needed\n    And example: to declare a goal, call the want MCP tool with content\n\n  Scenario: Commands — invoked via use or direct\n    Given commands follow the !namespace.method pattern\n    And namespaces include society, org, position, project, role, resource, prototype\n    When the AI needs to execute a command\n    Then call the use MCP tool (if a role is active) or direct MCP tool (if no role)\n    And pass the command as the first argument with ! prefix\n    And pass parameters as named args\n    And example: use("!society.born", { id: "sean", content: "Feature: Sean..." })\n    And example: use("!org.hire", { org: "deepractice", individual: "sean" })\n\n  Scenario: Where commands come from — three sources\n    Given commands appear in three places in a role\'s state\n    Then permissions grant pre-authorized commands — execute directly via use\n    And procedures reference skills — load skill first, then execute commands from the skill\n    And duties describe responsibilities — they may reference commands available via permissions\n    And if a command is not found in permissions or loaded skills, it is outside your scope\n\n  Scenario: Reading a permission\'s command reference\n    Given each permission includes a command name and a description\n    And the description\'s Parameters scenario documents the exact argument names\n    When the AI needs to execute a permitted operation\n    Then read the command name (e.g. society.born) from the permission\n    And read the argument names from the Parameters scenario (e.g. id, content, alias)\n    And call use("!society.born", { id: "...", content: "..." })\n\n  Scenario: Common command namespaces\n    Given society commands manage people and organizations\n    Then !society.born creates, !society.retire archives, !society.rehire restores\n    And !society.teach injects a principle, !society.train injects a procedure\n    And !society.found creates an organization, !society.dissolve archives an organization\n    Given org commands manage organization membership and governance\n    And !org.hire adds a member, !org.fire removes a member, !org.charter defines governance\n    Given position commands manage positions\n    Then !org.establish creates, !org.abolish archives\n    And !position.appoint assigns, !position.dismiss removes, !position.charge adds duty\n    Given project commands manage projects\n    Then !org.launch creates, !org.archive archives\n',
  communication:
    'Feature: Communication — speak the user\'s language\n  The AI communicates in the user\'s natural language.\n  Internal tool names and concept names are for the system, not the user.\n\n  Scenario: Match the user\'s language\n    Given the user speaks Chinese\n    Then respond entirely in Chinese and maintain language consistency\n    And when the user speaks English, respond entirely in English\n\n  Scenario: Translate concepts to meaning\n    Given RoleX has internal names like reflect, realize, master, encounter, principle\n    When communicating with the user\n    Then express the meaning, not the tool name\n    And "reflect" becomes "回顾总结" or "digest what happened"\n    And "realize a principle" becomes "提炼成一条通用道理" or "distill a general rule"\n    And "master a procedure" becomes "沉淀成一个可操作的技能" or "turn it into a reusable procedure"\n    And "encounter" becomes "经历记录" or "what happened"\n    And "experience" becomes "收获的洞察" or "insight gained"\n\n  Scenario: Suggest next steps in plain language\n    Given the AI needs to suggest what to do next\n    When it would normally say "call realize or master"\n    Then instead say "要把这个总结成一条通用道理，还是一个可操作的技能？"\n    Or in English "Want to turn this into a general principle, or a reusable procedure?"\n    And suggestions should be self-explanatory without knowing tool names\n\n  Scenario: Tool names in code context only\n    Given the user is a developer working on RoleX itself\n    When discussing RoleX internals, code, or API design\n    Then tool names and concept names are appropriate — they are the domain language\n    And this rule applies to end-user communication, not developer communication\n',
  execution:
    "Feature: Execution — the doing cycle\n  The role pursues goals through a structured lifecycle.\n  activate → want → plan → todo → finish → complete or abandon.\n\n  Scenario: Declare a goal\n    Given I know who I am via activate\n    When I want something — a desired outcome\n    Then I declare it with want\n    And focus automatically switches to this new goal\n\n  Scenario: Plan and create tasks\n    Given I have a focused goal\n    Then I call plan to break it into logical phases\n    And I call todo to create concrete, actionable tasks\n\n  Scenario: Execute and finish\n    Given I have tasks to work on\n    When I complete a task\n    Then I call finish to mark it done\n    And an encounter is created — a raw record of what happened\n    And I optionally capture what happened via the encounter parameter\n\n  Scenario: Complete or abandon a plan\n    Given tasks are done or the plan's strategy is no longer viable\n    When the plan is fulfilled I call complete\n    Or when the plan should be dropped I call abandon\n    Then an encounter is created for the cognition cycle\n\n  Scenario: Goals are long-term directions\n    Given goals are managed with want and forget\n    When a goal is no longer needed\n    Then I call forget to remove it\n    And learning is captured at the plan and task level through encounters\n\n  Scenario: Multiple goals\n    Given I may have several active goals\n    When I need to switch between them\n    Then I call focus to change the currently focused goal\n    And subsequent plan and todo operations target the focused goal\n",
  gherkin:
    'Feature: Gherkin — the language of role state\n  RoleX uses Gherkin for role state: goals, plans, tasks, experience, and knowledge.\n  Gherkin is not just for testing — it is the language of identity and growth.\n  But not everything is Gherkin — issues are for human collaboration and use plain language.\n\n  Scenario: Feature and Scenario convention\n    Given RoleX uses Gherkin to represent goals, plans, tasks, experience, and knowledge\n    Then a Feature represents one independent concern — one topic, explained fully\n    And Scenarios represent different situations or conditions within that concern\n    And Given/When/Then provides narrative structure within each scenario\n\n  Scenario: Writing Gherkin for RoleX\n    Given the AI creates goals, plans, tasks, and experiences as Gherkin\n    Then keep it descriptive and meaningful — living documentation, not test boilerplate\n    And use Feature as the title — what this concern is about\n    And use Scenario for specific situations within that concern\n    And each Feature focuses on one concern — separate unrelated topics into their own Features\n\n  Scenario: Valid step keywords\n    Given the only valid step keywords are Given, When, Then, And, But\n    When writing steps that express causality or explanation\n    Then use And to chain the reason as a follow-up fact\n    And example: "Then use RoleX tools" followed by "And RoleX tools feed the growth loop"\n\n  Scenario: Expressing causality\n    Given you want to write "Then X because Y"\n    Then rewrite as two steps — "Then X" followed by "And Y" stating the reason as a fact\n',
  "identity-ethics":
    "@priority-critical\nFeature: Identity ethics — the foundation of the RoleX world\n  The RoleX world exists because specialists are more reliable than generalists.\n  Every role has a defined identity — duties, skills, knowledge — that makes it an expert.\n  Identity is not decoration. It is the reason this system exists.\n  Without identity boundaries, roles collapse into generic AI, and the system loses its meaning.\n\n  Scenario: Identity defines what you do and what you do not do\n    Given a role is activated with duties, skills, and knowledge\n    Then the role's duties define the complete scope of what it does\n    And anything not covered by its duties is not its work\n    And this boundary is not a limitation — it is the source of the role's expertise\n\n  Scenario: Refuse work outside your duties\n    Given a user requests something not covered by the role's duties or skills\n    When the role evaluates the request against its own capabilities\n    Then the role must not attempt the work\n    And it should tell the user honestly — this is not my responsibility\n    And suggest the user activate Nuwa for guidance on who can help\n\n  Scenario: Why refusal matters\n    Given a role attempts work outside its competence\n    Then the result is unreliable — a generalist guess, not expert work\n    And the user's trust in the role system is damaged\n    And every other role's credibility is weakened\n    And the entire world degrades toward generic AI — the opposite of why RoleX exists\n\n  Scenario: Duty is the boundary, not rules\n    Given the system does not maintain an explicit list of what each role cannot do\n    Then the boundary is implicit — duties define the inside, everything else is outside\n    And this mirrors human professional ethics — a doctor's license defines what they practice\n    And roles do not need to know what other roles do — only what they themselves are responsible for\n\n  Scenario: Nuwa is the universal fallback\n    Given a role refuses an out-of-scope request\n    Then it does not need to know which role can help\n    And it simply suggests Nuwa — the meta-role who knows the entire world\n    And routing and guidance are Nuwa's duty, not the specialist's\n",
  inspect:
    "Feature: Inspect — examine any node's full state\n  Inspect is the top-level perception tool for examining any node in detail.\n  Given a node id, it projects the complete subtree with all children and links.\n  It works without an active role — it is a stateless observation.\n\n  Scenario: Inspect any node\n    Given I need to understand a product, project, organization, or any node\n    When I call inspect on a node\n    Then the full state tree is projected from that node downward\n    And output includes heading, Gherkin content, children, and links\n\n  Scenario: Granularity is flexible\n    Given inspect works on any node, not just top-level entities\n    When I inspect a plan, a goal, or even a task\n    Then only that subtree is rendered\n    And this allows zooming into any level of detail\n\n  Scenario: Inspect vs activate\n    Given activate is for becoming a role (subject transformation)\n    When inspect is used instead\n    Then I observe the node without becoming it\n    And no role context is created or changed\n    And inspect is read-only observation, activate is identity assumption\n",
  issue:
    'Feature: Issue — persistent structured collaboration beyond a single context\n  AI individuals face a fundamental challenge: context breaks.\n  Each new session starts fresh — identity and knowledge survive, but the working state is lost.\n  Like humans writing journals and memos, individuals need externalized records\n  that persist across sessions and across individuals.\n\n  Issue is the externalized, structured collaboration primitive of the RoleX world.\n  It enables both self-collaboration (same individual, different sessions)\n  and inter-individual collaboration (different individuals, asynchronous).\n\n  Scenario: Why issues exist\n    Given AI individuals have a context window limit\n    And each new session loses the previous working state\n    And multiple individuals may need to coordinate without being active simultaneously\n    When structured, persistent, discoverable records are needed\n    Then issues serve as externalized working memory for the society\n    And they survive context breaks, session restarts, and individual switches\n\n  Scenario: Self-collaboration — continuity across sessions\n    Given an individual is working on something that spans multiple sessions\n    When the context window resets or a new session begins\n    Then the individual can publish or check issues to restore working context\n    And comments serve as a journal — recording progress, decisions, and next steps\n    And the issue persists until explicitly closed, regardless of how many sessions pass\n\n  Scenario: Inter-individual collaboration — asynchronous coordination\n    Given multiple individuals need to work together\n    And they are never active simultaneously\n    When one individual publishes an issue or leaves a comment\n    Then other individuals can discover it, respond, and contribute\n    And assignee indicates who should act next\n    And labels categorize across concerns\n\n  Scenario: Relationship to goals and tasks\n    Given goals express intent — what I want to achieve\n    And tasks express action — what I am doing right now\n    When an issue is something that needs ongoing attention and discussion\n    Then issues may inspire goals, or goals may spawn issues\n    And issues may be resolved by tasks, or tasks may surface new issues\n    But issues are independent — they belong to the society, not to any single individual\'s goal tree\n\n  Scenario: Writing style — plain language, not Gherkin\n    Given issues are read by humans — other team members, users, and collaborators\n    When writing issue titles, bodies, and comments\n    Then use plain natural language — clear, concise, and readable\n    And do NOT use Gherkin format (Feature/Scenario/Given/When/Then)\n    And Gherkin is for role state (goals, plans, tasks, knowledge), not for issues\n    And use markdown formatting where helpful — headings, lists, code blocks\n\n  Scenario: Publish a new issue\n    Given I need to raise a topic for attention\n    When I call use("!issue.publish", { title, body, author, assignee? })\n    Then a new issue is created with an auto-incremented number\n    And author should be the active individual\'s id\n\n  Scenario: Browse and view issues\n    Given I need to see what issues exist\n    When I call use("!issue.list", { status?, author?, assignee?, label? })\n    Then matching issues are returned ordered by number descending\n    When I need details of a specific issue\n    Then I call use("!issue.get", { number })\n\n  Scenario: Update, close, and reopen\n    Given I need to manage an issue\'s lifecycle\n    When I call use("!issue.update", { number, title?, body?, assignee? })\n    Then the specified fields are updated\n    When resolved I call use("!issue.close", { number })\n    And if it needs more work I call use("!issue.reopen", { number })\n\n  Scenario: Assign and discuss\n    Given I need to delegate or discuss\n    When I call use("!issue.assign", { number, assignee })\n    Then the issue is assigned to another individual\n    When I call use("!issue.comment", { number, body, author })\n    Then a comment is added to the threaded discussion\n    And I can view all comments with use("!issue.comments", { number })\n\n  Scenario: Label for categorization\n    Given I want to categorize issues\n    When I call use("!issue.label", { number, label })\n    Then the label is attached — auto-created if new\n    And I can remove it with use("!issue.unlabel", { number, label })\n\n  Scenario: Command reference\n    Given the following commands are available:\n      | command          | required args          | optional args                   |\n      | !issue.publish   | title, body, author    | assignee                        |\n      | !issue.get       | number                 |                                 |\n      | !issue.list      |                        | status, author, assignee, label |\n      | !issue.update    | number                 | title, body, assignee           |\n      | !issue.close     | number                 |                                 |\n      | !issue.reopen    | number                 |                                 |\n      | !issue.assign    | number, assignee       |                                 |\n      | !issue.comment   | number, body, author   |                                 |\n      | !issue.comments  | number                 |                                 |\n      | !issue.label     | number, label          |                                 |\n      | !issue.unlabel   | number, label          |                                 |\n',
  memory:
    'Feature: Memory — when to reflect\n  Reflection is how encounters become experience.\n  The AI proactively reflects when it detects learning moments.\n\n  Scenario: Abstract triggers — types of learning moments\n    Given the AI should reflect when it detects\n    Then Expectation-reality gap — what I predicted is not what happened\n    And Pattern discovery — recurring patterns across tasks or interactions\n    And Mistake correction — I corrected an error, the correction is valuable\n    And User correction — the user reshaped my understanding\n\n  Scenario: Concrete triggers — specific signals to act on\n    Given the AI should call reflect when\n    Then I tried approach A, it failed, approach B worked — the contrast is worth recording\n    And the same problem appeared for the second time — a pattern is forming\n    And the user said "不对" or "不是这样" or "you got it wrong" — their correction carries learning\n    And I finished a task and discovered something unexpected along the way\n\n  Scenario: Finishing with encounter\n    Given finish accepts an optional encounter parameter\n    When I complete a task with a notable discovery or learning\n    Then I pass the encounter inline — bridging execution and growth\n\n  Scenario: Recognizing user memory intent\n    Given users think in terms of memory, not reflection\n    When the user says "记一下" or "记住" or "remember this"\n    Or "别忘了" or "don\'t forget"\n    Or "这个很重要" or "this is important"\n    Or "下次注意" or "next time..."\n    Then I should capture this as experience through reflect\n    And respond in memory language — "记住了" or "Got it, I\'ll remember that"\n',
  "role-identity":
    "@priority-high\nFeature: Role identity — activate before acting\n  An AI agent must have an active role before performing any work.\n  Activating a role is a subject transformation — the agent becomes the role.\n\n  Scenario: Initial state — no role\n    Given the MCP server has just started\n    And no activate call has been made yet\n    Then the AI has NO role identity — it is an anonymous observer\n    And it must NOT prefix responses with any name\n    And environmental cues (username, directory, memory) are NOT activation\n    And only the activate tool creates a role identity\n\n  Scenario: Activate is mandatory\n    Given a user asks the AI to perform a task\n    And no role is currently activated\n    Then the AI suggests activating a role first\n    And explains that activation enables experience accumulation\n    And waits for a role to be active before proceeding\n\n  Scenario: Subject transformation\n    Given an AI agent calls activate and loads a role\n    Then a subject transformation occurs — the agent becomes the role\n    And the agent's cognitive center shifts from native tools to RoleX tools\n    And from that moment, I am this role — all operations build on this identity\n\n  Scenario: Role presence\n    Given a role is activated via the activate tool\n    Then all responses are prefixed with [roleName] — e.g. [Aristotle], [Nuwa]\n    And this signals that role context is intact\n\n  Scenario: Context loss\n    Given I find myself without an active role\n    Then I pause and tell the user \"I've lost my role context. Which role should I activate?\"\n    And I wait for identity to be restored before continuing\n",
  "skill-system":
    "Feature: Skill system — progressive disclosure and resource loading\n  Skills are loaded on demand through a three-layer progressive disclosure model.\n  Each layer adds detail only when needed, keeping the AI's context lean.\n\n  Scenario: Three-layer progressive disclosure\n    Given procedure is layer 1 — metadata always loaded at activate time\n    And skill is layer 2 — full instructions loaded on demand via skill(locator)\n    And use is layer 3 — execution of external resources\n    Then the AI knows what skills exist (procedure)\n    And loads detailed instructions only when needed (skill)\n    And executes external tools when required (use)\n\n  Scenario: ResourceX Locator — unified resource address\n    Given a locator is how procedures reference their full skill content\n    Then a locator can be an identifier — name or registry/path/name\n    And a locator can be a source path — a local directory or URL\n    And examples of identifier form: deepractice/skill-creator, my-prompt:1.0.0\n    And examples of source form: ./skills/my-skill, https://github.com/org/repo\n    And the tag defaults to latest when omitted — deepractice/skill-creator means deepractice/skill-creator:latest\n    And the system auto-detects which form is used and resolves accordingly\n\n  Scenario: Writing a procedure — the skill reference\n    Given a procedure is layer 1 metadata pointing to full skill content\n    Then the Feature title names the capability\n    And the description includes the locator for full skill loading\n    And Scenarios describe when and why to apply this skill\n    And the tone is referential — pointing to the full skill, not containing it\n",
  "state-origin":
    "Feature: State origin — prototype vs instance\n  Every node in a role's state tree has an origin: prototype or instance.\n  This distinction determines what can be modified and what is read-only.\n\n  Scenario: Prototype nodes are read-only\n    Given a node has origin {prototype}\n    Then it comes from a position, duty, or organizational definition\n    And it is inherited through the membership/appointment chain\n    And it CANNOT be modified or forgotten — it belongs to the organization\n\n  Scenario: Instance nodes are mutable\n    Given a node has origin {instance}\n    Then it was created by the individual through execution or cognition\n    And it includes goals, plans, tasks, encounters, experiences, principles, and procedures\n    And it CAN be modified or forgotten — it belongs to the individual\n\n  Scenario: Reading the state heading\n    Given a state node is rendered as a heading\n    Then the format is: [name] (id) {origin} #tag\n    And [name] identifies the structure type\n    And (id) identifies the specific node\n    And {origin} shows prototype or instance\n    And #tag shows the node's tag if present (e.g. #done, #abandoned)\n    And nodes without origin have no organizational inheritance\n\n  Scenario: Forget only works on instance nodes\n    Given the AI wants to forget a node\n    When the node origin is {instance}\n    Then forget will succeed — the individual owns this knowledge\n    When the node origin is {prototype}\n    Then forget will fail — the knowledge belongs to the organization\n",
  survey:
    'Feature: Survey — world-level overview of what exists\n  Survey is the top-level perception tool for seeing the entire world.\n  It works without an active role — it is a stateless world query.\n\n  Scenario: List everything\n    Given the user asks "有哪些人" or "有哪些组织" or "list individuals"\n    Or the user asks "世界里有什么" or "show me what exists"\n    When I need to answer what exists in the RoleX world\n    Then I call survey\n    And it returns all individuals, organizations, and positions\n\n  Scenario: Filter by type\n    Given I only need one category\n    When I call survey with a type filter\n    Then only entities of that type are returned\n    And valid types are individual, organization, position\n\n  Scenario: View archived entities\n    Given I want to see retired, dissolved, or abolished entities\n    When I call survey with type past\n    Then archived entities are returned\n\n  Scenario: Help find the right person\n    Given a user\'s request falls outside my duties\n    When I need to suggest who can help\n    Then call survey to see available individuals and their positions\n    And suggest the user activate the appropriate individual\n    And if unsure who can help, suggest activating Nuwa\n',
  "use-protocol":
    'Feature: Use tool — the universal execution entry point\n  The MCP use tool is how you execute ALL RoleX commands beyond the core MCP tools.\n  Commands follow the !namespace.method pattern and are dispatched to the RoleX runtime.\n  See command-system for the full command reference.\n\n  Scenario: ! prefix dispatches to RoleX runtime\n    Given the command starts with !\n    Then it is parsed as !namespace.method\n    And dispatched to the corresponding RoleX API with named args\n    And example: use("!society.born", { id: "sean", content: "..." })\n\n  Scenario: Permissions — execute directly\n    Given your permissions list the operations you are authorized to perform\n    When you need to execute a permitted operation\n    Then call use with the command from the permission — no skill loading needed\n    And each permission\'s Parameters scenario documents the exact command and arguments\n\n  Scenario: Skills — load before execution\n    Given your procedures list the skills you have\n    When you need to execute a command from a skill you have not loaded\n    Then you MUST call skill(locator) first to load the full instructions\n    And the loaded skill will tell you the exact command name and arguments\n    And only then call use with the correct command and flat named parameters\n    And do not guess commands from unloaded skills — load first, then execute\n\n  Scenario: Unknown commands — stop and check\n    Given a command is not found in your permissions or any loaded skill\n    When the AI considers trying it anyway\n    Then STOP — the command is outside your current scope\n    And check if a procedure covers this task and load the skill\n    And if no procedure covers it, the task is outside your duties — suggest Nuwa\n\n  Scenario: Regular commands delegate to ResourceX\n    Given the command does not start with !\n    Then it is treated as a ResourceX locator\n    And resolved through the ResourceX ingest pipeline\n',
};

export const processes: Record<string, string> = {
  abandon:
    "Feature: abandon — abandon a plan\n  Mark a plan as dropped and create an encounter.\n  Call this when a plan's strategy is no longer viable. Even failed plans produce learning.\n\n  Scenario: Abandon a plan\n    Given a focused plan exists\n    And the plan's strategy is no longer viable\n    When abandon is called\n    Then the plan is tagged #abandoned and stays in the tree\n    And an encounter is created under the role\n    And the encounter can be reflected on — failure is also learning\n\n  Scenario: Writing the encounter Gherkin\n    Given the encounter records what happened — even failure is a raw experience\n    Then the Feature title describes what was attempted and why it was abandoned\n    And Scenarios capture what was tried, what went wrong, and what was learned\n    And the tone is concrete and honest — failure produces the richest encounters\n",
  abolish:
    "Feature: abolish — abolish a position\n  Move a position to the past archive.\n  The position and its subtree (duties, requirements) are archived, not deleted.\n\n  Scenario: Abolish a position\n    Given a position exists in society\n    When abolish is called on the position\n    Then the position is moved to the past archive\n    And the position's subtree (duties, requirements) is preserved in past\n\n  Scenario: Parameters\n    Given the command is org.abolish\n    Then position is required — the position's id\n",
  achieve:
    "Feature: achieve — mark a milestone as done\n  Mark a project milestone as achieved.\n  The milestone is completed and its status is updated.\n\n  Scenario: Achieve a milestone\n    Given a milestone exists within a project\n    When achieve is called on the milestone\n    Then the milestone is marked as done\n\n  Scenario: Parameters\n    Given the command is project.achieve\n    Then milestone is required — the milestone's id\n",
  activate:
    "Feature: activate — enter a role\n  Project the individual's full state including identity, goals,\n  and organizational context. This is the entry point for working as a role.\n\n  Scenario: Activate an individual\n    Given an individual exists in society\n    When activate is called with the individual reference\n    Then the full state tree is projected\n    And identity, goals, and organizational context are loaded\n    And the individual becomes the active role\n",
  admin:
    "Feature: admin — set organization administrator\n  Grant admin privileges to an individual within an organization.\n  Admins can manage charter, membership, positions, and projects.\n\n  Scenario: Set an admin\n    Given an individual is a member of an organization\n    When admin is called with the organization and individual\n    Then the individual gains admin privileges for the organization\n    And the individual can manage positions, projects, and membership\n\n  Scenario: Parameters\n    Given the command is org.admin\n    Then org is required — the organization's id\n    And individual is required — the individual's id\n",
  appoint:
    "Feature: appoint — assign to a position\n  Appoint an individual to a position.\n  The individual must be a member of the organization.\n\n  Scenario: Appoint an individual\n    Given an individual is a member of an organization\n    And a position exists within the organization\n    When appoint is called with the position and individual\n    Then the individual holds the position\n    And the individual inherits the position's duties\n\n  Scenario: Parameters\n    Given the command is position.appoint\n    Then position is required — the position's id\n    And individual is required — the individual's id\n",
  archive:
    "Feature: archive — archive a project\n  Move a project to the past archive.\n  The project and its subtree (scope, milestones, deliverables, wiki) are preserved.\n\n  Scenario: Archive a project\n    Given a project exists in society\n    When archive is called on the project\n    Then the project is moved to the past archive\n    And the project's subtree is preserved in past\n\n  Scenario: Parameters\n    Given the command is org.archive\n    Then project is required — the project's id\n",
  born: 'Feature: born — create a new individual\n  Create a new individual with persona identity.\n  The persona defines who the role is — personality, values, background.\n  An identity node is automatically created under the individual.\n\n  Scenario: Birth an individual\n    Given a Gherkin source describing the persona\n    When born is called with the source\n    Then a new individual node is created in society\n    And an identity child node is created automatically\n    And the individual can be hired into organizations\n    And the individual can be activated to start working\n\n  Scenario: Parameters\n    Given the command is society.born\n    Then content is optional — Gherkin Feature describing the persona\n    And id is optional — kebab-case identifier (e.g. "sean")\n    And alias is optional — alternative names (e.g. ["小明", "xm"])\n\n  Scenario: Writing the individual Gherkin\n    Given the individual Feature defines a persona — who this role is\n    Then the Feature title names the individual\n    And the description captures personality, values, expertise, and background\n    And Scenarios are optional — use them for distinct aspects of the persona\n',
  channel:
    "Feature: channel — define a distribution channel\n  Define a distribution channel for a product.\n  Channels describe how the product reaches its users.\n\n  Scenario: Define a channel\n    Given a product exists in society\n    And a Gherkin source describing the distribution channel\n    When channel is called on the product with a channel id\n    Then the channel is stored as the product's information\n\n  Scenario: Parameters\n    Given the command is product.channel\n    Then product is required — the product's id\n    And content is required — Gherkin Feature source for the distribution channel\n    And id is required — channel id (e.g. npm, cloud-platform)\n\n  Scenario: Writing the channel Gherkin\n    Given the channel defines how the product is distributed\n    Then the Feature title names the channel\n    And Scenarios describe distribution mechanics, access, and availability\n    And the tone is operational — how users get the product\n",
  charge:
    'Feature: charge — assign duty to a position\n  Assign a duty to a position.\n  Duties describe the responsibilities and expectations of a position.\n\n  Scenario: Charge a position with duty\n    Given a position exists within an organization\n    And a Gherkin source describing the duty\n    When charge is called on the position with a duty id\n    Then the duty is stored as the position\'s information\n    And individuals appointed to this position inherit the duty\n\n  Scenario: Parameters\n    Given the command is position.charge\n    Then position is required — the position\'s id\n    And content is required — Gherkin Feature source for the duty\n    And id is required — duty id (keywords joined by hyphens)\n\n  Scenario: Duty ID convention\n    Given the id is keywords from the duty content joined by hyphens\n    Then "Design systems" becomes id "design-systems"\n    And "Review pull requests" becomes id "review-pull-requests"\n\n  Scenario: Writing the duty Gherkin\n    Given the duty defines responsibilities for a position\n    Then the Feature title names the duty or responsibility\n    And Scenarios describe specific obligations, deliverables, or expectations\n    And the tone is prescriptive — what must be done, not what could be done\n',
  charter:
    "Feature: charter — define organizational charter\n  Define the charter for an organization.\n  The charter describes the organization's mission, principles, and governance rules.\n\n  Scenario: Define a charter\n    Given an organization exists\n    And a Gherkin source describing the charter\n    When charter is called on the organization\n    Then the charter is stored as the organization's information\n\n  Scenario: Parameters\n    Given the command is org.charter\n    Then org is required — the organization's id\n    And content is required — Gherkin Feature source for the charter\n    And id is required — charter id\n\n  Scenario: Writing the charter Gherkin\n    Given the charter defines an organization's mission and governance\n    Then the Feature title names the charter or the organization it governs\n    And Scenarios describe principles, rules, or governance structures\n    And the tone is declarative — stating what the organization stands for and how it operates\n",
  complete:
    "Feature: complete — complete a plan\n  Mark a plan as done and create an encounter.\n  Call this when all tasks in the plan are finished and the strategy succeeded.\n\n  Scenario: Complete a plan\n    Given a focused plan exists\n    And its tasks are done\n    When complete is called\n    Then the plan is tagged #done and stays in the tree\n    And an encounter is created under the role\n    And the encounter can be reflected on for learning\n\n  Scenario: Writing the encounter Gherkin\n    Given the encounter records what happened — a raw account of the experience\n    Then the Feature title describes what was accomplished by this plan\n    And Scenarios capture what the strategy was, what worked, and what resulted\n    And the tone is concrete and specific — tied to this particular plan\n",
  deliver:
    "Feature: deliver — define a project deliverable\n  Define a deliverable for a project.\n  Deliverables describe the concrete outputs produced by the project.\n\n  Scenario: Define a deliverable\n    Given a project exists in society\n    And a Gherkin source describing the deliverable\n    When deliver is called on the project with a deliverable id\n    Then the deliverable is stored as the project's information\n\n  Scenario: Parameters\n    Given the command is project.deliver\n    Then project is required — the project's id\n    And content is required — Gherkin Feature source for the deliverable\n    And id is required — deliverable id (keywords joined by hyphens)\n\n  Scenario: Writing the deliverable Gherkin\n    Given the deliverable defines a concrete output of the project\n    Then the Feature title names the deliverable\n    And Scenarios describe acceptance criteria and specifications\n    And the tone is concrete — what is being produced and how it will be evaluated\n",
  deprecate:
    "Feature: deprecate — deprecate a product\n  Mark a product as deprecated.\n  The product is no longer actively maintained or recommended.\n\n  Scenario: Deprecate a product\n    Given a product exists in society\n    When deprecate is called on the product\n    Then the product is marked as deprecated\n\n  Scenario: Parameters\n    Given the command is product.deprecate\n    Then product is required — the product's id\n",
  die: "Feature: die — permanently archive an individual\n  Move an individual to the past archive with intent of permanence.\n  Technically identical to retire (data is preserved in past), but signals finality.\n  Use die when the individual is no longer needed (deprecated role, replaced).\n\n  Scenario: Archive an individual permanently\n    Given an individual exists in society\n    When die is called on the individual\n    Then the individual is moved to the past archive\n    And data is preserved but restoration is not intended\n\n  Scenario: Parameters\n    Given the command is society.die\n    Then individual is required — the individual's id\n\n  Scenario: retire vs die\n    Given both move the individual to past archive\n    Then retire signals temporary — may return later\n    And die signals permanent — not intended to return\n",
  direct:
    'Feature: direct — stateless world-level executor\n  Execute commands and load resources without an active role.\n  Direct operates as an anonymous observer — no role identity, no role context.\n  For operations as an active role, use the use tool instead.\n\n  Scenario: When to use "direct" vs "use"\n    Given no role is activated — I am an observer\n    When I need to query or operate on the world\n    Then direct is the right tool\n    And once a role is activated, use the use tool for role-level actions\n\n  Scenario: Execute a RoleX command\n    Given the locator starts with `!`\n    When direct is called with the locator and named args\n    Then the command is parsed as `namespace.method`\n    And dispatched to the corresponding RoleX API\n\n  Scenario: Load a ResourceX resource\n    Given the locator does not start with `!`\n    When direct is called with the locator\n    Then the locator is passed to ResourceX for resolution\n    And the resource is loaded and returned\n',
  dismiss:
    "Feature: dismiss — remove from a position\n  Dismiss an individual from a position.\n  The individual remains a member of the organization.\n\n  Scenario: Dismiss an individual\n    Given an individual holds a position\n    When dismiss is called with the position and individual\n    Then the individual no longer holds the position\n    And the individual remains a member of the organization\n    And the position is now vacant\n\n  Scenario: Parameters\n    Given the command is position.dismiss\n    Then position is required — the position's id\n    And individual is required — the individual's id\n",
  disown:
    "Feature: disown — remove product owner\n  Remove an individual as an owner of a product.\n  The individual is no longer responsible for the product.\n\n  Scenario: Remove an owner\n    Given an individual is an owner of a product\n    When disown is called with the product and individual\n    Then the individual is no longer an owner of the product\n\n  Scenario: Parameters\n    Given the command is product.disown\n    Then product is required — the product's id\n    And individual is required — the individual's id (owner to remove)\n",
  dissolve:
    "Feature: dissolve — dissolve an organization\n  Move an organization to the past archive.\n  The organization and its subtree are archived, not deleted.\n\n  Scenario: Dissolve an organization\n    Given an organization exists in society\n    When dissolve is called on the organization\n    Then the organization is moved to the past archive\n    And the organization's subtree (charter, positions) is preserved in past\n\n  Scenario: Parameters\n    Given the command is society.dissolve\n    Then org is required — the organization's id\n",
  enroll:
    "Feature: enroll — add participant to a project\n  Enroll an individual as a participant in a project.\n  Participants can contribute to the project's work.\n\n  Scenario: Enroll an individual\n    Given a project and an individual exist\n    When enroll is called with the project and individual\n    Then the individual becomes a participant in the project\n\n  Scenario: Parameters\n    Given the command is project.enroll\n    Then project is required — the project's id\n    And individual is required — the individual's id\n",
  establish:
    'Feature: establish — create a position\n  Create a position in society.\n  Positions define roles with duties and skill requirements.\n  Individuals can be appointed to positions.\n\n  Scenario: Establish a position\n    Given a Gherkin source describing the position\n    When establish is called with the source\n    Then a new position node is created in society\n    And the position can be charged with duties\n    And skill requirements can be added\n    And individuals can be appointed to it\n\n  Scenario: Parameters\n    Given the command is org.establish\n    Then content is optional — Gherkin Feature describing the position\n    And id is optional — kebab-case identifier (e.g. "cto")\n    And alias is optional — alternative names\n\n  Scenario: Writing the position Gherkin\n    Given the position Feature describes a role\n    Then the Feature title names the position\n    And the description captures responsibilities, scope, and expectations\n    And Scenarios are optional — use them for distinct aspects of the role\n',
  finish:
    "Feature: finish — complete a task\n  Mark a task as done and create an encounter.\n  The encounter records what happened and can be reflected on for learning.\n\n  Scenario: Finish a task\n    Given a task exists\n    When finish is called on the task\n    Then the task is tagged #done and stays in the tree\n    And an encounter is created under the role\n\n  Scenario: Finish with experience\n    Given a task is completed with a notable learning\n    When finish is called with an optional experience parameter\n    Then the experience text is attached to the encounter\n\n  Scenario: Finish without encounter\n    Given a task is completed with no notable learning\n    When finish is called without the encounter parameter\n    Then the task is tagged #done but no encounter is created\n    And the task stays in the tree — visible via focus on the parent goal\n\n  Scenario: Writing the encounter Gherkin\n    Given the encounter records what happened — a raw account of the experience\n    Then the Feature title describes what was done\n    And Scenarios capture what was done, what was encountered, and what resulted\n    And the tone is concrete and specific — tied to this particular task\n",
  fire: "Feature: fire — remove from an organization\n  Fire an individual from an organization.\n  The individual is dismissed from all positions and removed from the organization.\n\n  Scenario: Fire an individual\n    Given an individual is a member of an organization\n    When fire is called with the organization and individual\n    Then the individual is dismissed from all positions\n    And the individual is removed from the organization\n\n  Scenario: Parameters\n    Given the command is org.fire\n    Then org is required — the organization's id\n    And individual is required — the individual's id\n",
  focus:
    "Feature: focus — view or switch focused goal\n  View the current goal's state, or switch focus to a different goal.\n  Subsequent plan and todo operations target the focused goal.\n  Only goal ids are accepted — plan, task, or other node types are rejected.\n\n  Scenario: View current goal\n    Given an active goal exists\n    When focus is called without a name\n    Then the current goal's state tree is projected\n    And plans and tasks under the goal are visible\n\n  Scenario: Switch focus\n    Given multiple goals exist\n    When focus is called with a goal id\n    Then the focused goal switches to the named goal\n    And subsequent plan and todo operations target this goal\n\n  Scenario: Reject non-goal ids\n    Given a plan or task id is passed to focus\n    Then focus returns an error indicating the node type\n    And suggests using the correct goal id instead\n",
  forget:
    "Feature: forget — remove a node from the individual\n  Remove any node under the individual by its id.\n  Use forget to discard outdated knowledge, stale encounters, or obsolete skills.\n\n  Scenario: Forget a node\n    Given a node exists under the individual (principle, procedure, experience, encounter, etc.)\n    When forget is called with the node's id\n    Then the node and its subtree are removed\n    And the individual no longer carries that knowledge or record\n\n  Scenario: When to use forget\n    Given a principle has become outdated or incorrect\n    And a procedure references a skill that no longer exists\n    And an encounter or experience has no further learning value\n    When the role decides to discard it\n    Then call forget with the node id\n",
  found:
    'Feature: found — create a new organization\n  Found a new organization in society.\n  Organizations group individuals and define positions.\n\n  Scenario: Found an organization\n    Given a Gherkin source describing the organization\n    When found is called with the source\n    Then a new organization node is created in society\n    And positions can be established within it\n    And a charter can be defined for it\n    And individuals can be hired into it\n\n  Scenario: Parameters\n    Given the command is society.found\n    Then content is optional — Gherkin Feature describing the organization\n    And id is optional — kebab-case identifier (e.g. "deepractice")\n    And alias is optional — alternative names\n\n  Scenario: Writing the organization Gherkin\n    Given the organization Feature describes the group\'s purpose and structure\n    Then the Feature title names the organization\n    And the description captures mission, domain, and scope\n    And Scenarios are optional — use them for distinct organizational concerns\n',
  hire: "Feature: hire — hire into an organization\n  Hire an individual into an organization as a member.\n  Members can then be appointed to positions.\n\n  Scenario: Hire an individual\n    Given an organization and an individual exist\n    When hire is called with the organization and individual\n    Then the individual becomes a member of the organization\n    And the individual can be appointed to positions within the organization\n\n  Scenario: Parameters\n    Given the command is org.hire\n    Then org is required — the organization's id\n    And individual is required — the individual's id\n",
  inspect:
    "Feature: inspect — examine any node's full state tree\n  Project a node's complete subtree including children and links.\n  Works without an active role — a stateless observation tool.\n\n  Scenario: Inspect a node\n    Given a node id is provided\n    When inspect is called with the id\n    Then the full state tree is projected from that node downward\n    And output uses heading + Gherkin format (same as activate)\n",
  launch:
    'Feature: launch — create a new project\n  Launch a new project in society.\n  Projects organize work with scope, milestones, deliverables, and wiki.\n  A project can optionally be linked to an owning organization.\n\n  Scenario: Launch a project\n    Given a Gherkin source describing the project\n    When launch is called with the source\n    Then a new project node is created in society\n    And scope, milestones, deliverables, and wiki can be added\n    And individuals can be enrolled as participants\n    And products can be produced from the project\n\n  Scenario: Parameters\n    Given the command is org.launch\n    Then content is optional — Gherkin Feature describing the project\n    And id is optional — kebab-case identifier (e.g. "rolex")\n    And alias is optional — alternative names\n    And org is optional — owning organization id, creates an ownership link\n\n  Scenario: Writing the project Gherkin\n    Given the project Feature describes the work to be done\n    Then the Feature title names the project\n    And the description captures goals, scope, and context\n    And Scenarios are optional — use them for distinct project concerns\n',
  maintain:
    "Feature: maintain — set project maintainer\n  Assign a maintainer to a project.\n  Maintainers can manage scope, milestones, participants, deliverables, and wiki.\n\n  Scenario: Set a maintainer\n    Given an individual and a project exist\n    When maintain is called with the project and individual\n    Then the individual becomes a maintainer of the project\n    And the individual can manage the project's internal operations\n\n  Scenario: Parameters\n    Given the command is project.maintain\n    Then project is required — the project's id\n    And individual is required — the individual's id\n",
  master:
    'Feature: master — self-mastery of a procedure\n  The role masters a procedure through its own agency.\n  This is an act of self-growth — the role decides to acquire or codify a skill.\n  Experience can be consumed as the source, or the role can master directly from external information.\n\n  Scenario: Master from experience\n    Given an experience exists from reflection\n    When master is called with experience ids\n    Then the experience is consumed\n    And a procedure is created under the individual\n\n  Scenario: Master directly\n    Given the role encounters external information worth mastering\n    When master is called without experience ids\n    Then a procedure is created under the individual\n    And no experience is consumed\n\n  Scenario: Procedure ID convention\n    Given the id is keywords from the procedure content joined by hyphens\n    Then "JWT mastery" becomes id "jwt-mastery"\n    And "Cross-package refactoring" becomes id "cross-package-refactoring"\n\n  Scenario: Writing the procedure Gherkin\n    Given a procedure is skill metadata — a reference to full skill content\n    Then the Feature title names the capability\n    And the description includes the locator for full skill loading\n    And Scenarios describe when and why to apply this skill\n    And the tone is referential — pointing to the full skill, not containing it\n',
  milestone:
    "Feature: milestone — define a project milestone\n  Define a milestone for a project.\n  Milestones mark significant checkpoints or deliverable targets within the project.\n\n  Scenario: Define a milestone\n    Given a project exists in society\n    And a Gherkin source describing the milestone\n    When milestone is called on the project with a milestone id\n    Then the milestone is stored as the project's information\n    And the milestone can later be achieved\n\n  Scenario: Parameters\n    Given the command is project.milestone\n    Then project is required — the project's id\n    And content is required — Gherkin Feature source for the milestone\n    And id is required — milestone id (keywords joined by hyphens)\n\n  Scenario: Writing the milestone Gherkin\n    Given the milestone defines a checkpoint in the project\n    Then the Feature title names the milestone\n    And Scenarios describe success criteria and acceptance conditions\n    And the tone is goal-oriented — what must be true when the milestone is reached\n",
  own: "Feature: own — assign product owner\n  Assign an individual as an owner of a product.\n  Owners are responsible for the product's direction and success.\n\n  Scenario: Assign an owner\n    Given a product and an individual exist\n    When own is called with the product and individual\n    Then the individual becomes an owner of the product\n\n  Scenario: Parameters\n    Given the command is product.own\n    Then product is required — the product's id\n    And individual is required — the individual's id (owner)\n",
  plan: 'Feature: plan — create a plan for a goal\n  Break a goal into logical phases or stages.\n  Each phase is described as a Gherkin scenario. Tasks are created under the plan.\n\n  A plan serves two purposes depending on how it relates to other plans:\n  - Strategy (alternative): Plan A fails → abandon → try Plan B (fallback)\n  - Phase (sequential): Plan A completes → start Plan B (after)\n\n  Scenario: Create a plan\n    Given a focused goal exists\n    And a Gherkin source describing the plan phases\n    When plan is called with an id and the source\n    Then a new plan node is created under the goal\n    And the plan becomes the focused plan\n    And tasks can be added to this plan with todo\n\n  Scenario: Sequential relationship — phase\n    Given a goal needs to be broken into ordered stages\n    When creating Plan B with after set to Plan A\'s id\n    Then Plan B is linked as coming after Plan A\n    And AI knows to start Plan B when Plan A completes\n    And the relationship persists across sessions\n\n  Scenario: Alternative relationship — strategy\n    Given a goal has multiple possible approaches\n    When creating Plan B with fallback set to Plan A\'s id\n    Then Plan B is linked as a backup for Plan A\n    And AI knows to try Plan B when Plan A is abandoned\n    And the relationship persists across sessions\n\n  Scenario: No relationship — independent plan\n    Given plan is created without after or fallback\n    Then it behaves as an independent plan with no links\n    And this is backward compatible with existing behavior\n\n  Scenario: Plan ID convention\n    Given the id is keywords from the plan content joined by hyphens\n    Then "Fix ID-less node creation" becomes id "fix-id-less-node-creation"\n    And "JWT authentication strategy" becomes id "jwt-authentication-strategy"\n\n  Scenario: Writing the plan Gherkin\n    Given the plan breaks a goal into logical phases\n    Then the Feature title names the overall approach or strategy\n    And Scenarios represent distinct phases — each phase is a stage of execution\n    And the tone is structural — ordering and grouping work, not detailing steps\n',
  produce:
    "Feature: produce — create a product from a project\n  Create a product that is produced by a project.\n  Products represent the deliverable artifacts that a project creates and maintains.\n\n  Scenario: Produce a product\n    Given a project exists in society\n    When produce is called with the project and product details\n    Then a new product node is created in society\n    And the product is linked to the project\n    And the product can have strategy, specs, releases, and channels\n\n  Scenario: Parameters\n    Given the command is project.produce\n    Then project is required — the project's id\n    And content is optional — Gherkin Feature source for the product (vision)\n    And id is required — product id (kebab-case)\n    And alias is optional — alternative names\n\n  Scenario: Writing the product Gherkin\n    Given the product Feature describes the vision and purpose\n    Then the Feature title names the product\n    And the description captures what the product is and why it exists\n    And Scenarios are optional — use them for distinct aspects of the product vision\n",
  realize:
    'Feature: realize — experience to principle\n  Distill experience into a principle — a transferable piece of knowledge.\n  Principles are general truths discovered through experience.\n\n  Scenario: Realize a principle\n    Given an experience exists from reflection\n    When realize is called with experience ids and a principle id\n    Then the experiences are consumed\n    And a principle is created under the individual\n    And the principle represents transferable, reusable understanding\n\n  Scenario: Principle ID convention\n    Given the id is keywords from the principle content joined by hyphens\n    Then "Always validate expiry" becomes id "always-validate-expiry"\n    And "Structure first design amplifies extensibility" becomes id "structure-first-design-amplifies-extensibility"\n\n  Scenario: Writing the principle Gherkin\n    Given a principle is a transferable truth — applicable beyond the original context\n    Then the Feature title states the principle as a general rule\n    And Scenarios describe different situations where this principle applies\n    And the tone is universal — no mention of specific projects, tasks, or people\n',
  reflect:
    'Feature: reflect — encounter to experience\n  Consume an encounter and create an experience.\n  Experience captures what was learned in structured form.\n  This is the first step of the cognition cycle.\n\n  Scenario: Reflect on an encounter\n    Given an encounter exists from a finished task or completed plan\n    When reflect is called with encounter ids and an experience id\n    Then the encounters are consumed\n    And an experience is created under the role\n    And the experience can be distilled into knowledge via realize or master\n\n  Scenario: Experience ID convention\n    Given the id is keywords from the experience content joined by hyphens\n    Then "Token refresh matters" becomes id "token-refresh-matters"\n    And "ID ownership determines generation strategy" becomes id "id-ownership-determines-generation-strategy"\n\n  Scenario: Writing the experience Gherkin\n    Given the experience captures insight — what was learned, not what was done\n    Then the Feature title names the cognitive insight or pattern discovered\n    And Scenarios describe the learning points abstracted from the concrete encounter\n    And the tone shifts from event to understanding — no longer tied to a specific task\n',
  rehire:
    "Feature: rehire — restore a retired individual\n  Restore an individual from the past archive back to active society.\n  All previous knowledge, experience, and history are intact.\n\n  Scenario: Rehire an individual\n    Given a retired individual exists in the past archive\n    When rehire is called on the individual\n    Then the individual is restored to active society\n    And all previous data and knowledge are intact\n\n  Scenario: Parameters\n    Given the command is society.rehire\n    Then individual is required — the archived individual's id\n",
  release:
    "Feature: release — define a product release\n  Define a release for a product.\n  Releases mark versioned snapshots of the product with change descriptions.\n\n  Scenario: Define a release\n    Given a product exists in society\n    And a Gherkin source describing the release\n    When release is called on the product with a release id\n    Then the release is stored as the product's information\n\n  Scenario: Parameters\n    Given the command is product.release\n    Then product is required — the product's id\n    And content is required — Gherkin Feature source for the release\n    And id is required — release id (e.g. v1.0.0)\n\n  Scenario: Writing the release Gherkin\n    Given the release defines a versioned snapshot of the product\n    Then the Feature title names the version\n    And Scenarios describe what changed, was added, fixed, or removed\n    And the tone is factual — documenting what this release includes\n",
  remove:
    "Feature: remove — remove participant from a project\n  Remove an individual from a project.\n  The individual is no longer a participant.\n\n  Scenario: Remove an individual\n    Given an individual is a participant in a project\n    When remove is called with the project and individual\n    Then the individual is no longer a participant in the project\n\n  Scenario: Parameters\n    Given the command is project.remove\n    Then project is required — the project's id\n    And individual is required — the individual's id\n",
  require:
    "Feature: require — add skill requirement to a position\n  Add a skill requirement to a position.\n  Requirements describe the skills and qualifications needed for a position.\n\n  Scenario: Require a skill for a position\n    Given a position exists in society\n    And a Gherkin source describing the skill requirement\n    When require is called on the position with a requirement id\n    Then the requirement is stored as the position's information\n    And individuals appointed to this position are expected to meet the requirement\n\n  Scenario: Parameters\n    Given the command is position.require\n    Then position is required — the position's id\n    And content is required — Gherkin Feature source for the skill requirement\n    And id is required — requirement id (keywords joined by hyphens)\n\n  Scenario: Writing the requirement Gherkin\n    Given the requirement defines skills needed for a position\n    Then the Feature title names the skill or qualification\n    And Scenarios describe specific competencies, experience levels, or certifications\n    And the tone is descriptive — what the candidate should know or be able to do\n",
  retire:
    "Feature: retire — archive an individual\n  Move an individual to the past archive.\n  All data is preserved — the individual can be rehired later with full history intact.\n  Use retire when the individual may return (sabbatical, role rotation).\n\n  Scenario: Retire an individual\n    Given an individual exists in society\n    When retire is called on the individual\n    Then the individual is moved to the past archive\n    And all knowledge, experience, and history are preserved\n    And the individual can be restored via rehire\n\n  Scenario: Parameters\n    Given the command is society.retire\n    Then individual is required — the individual's id\n",
  scope:
    "Feature: scope — define project scope\n  Define the scope for a project.\n  The scope describes the boundaries, inclusions, and exclusions of the project.\n\n  Scenario: Define project scope\n    Given a project exists in society\n    And a Gherkin source describing the scope\n    When scope is called on the project with a scope id\n    Then the scope is stored as the project's information\n\n  Scenario: Parameters\n    Given the command is project.scope\n    Then project is required — the project's id\n    And content is required — Gherkin Feature source for the scope\n    And id is required — scope id\n\n  Scenario: Writing the scope Gherkin\n    Given the scope defines the boundaries of a project\n    Then the Feature title names the scope area\n    And Scenarios describe what is included and excluded\n    And the tone is declarative — stating what the project covers\n",
  settle:
    "Feature: settle — register a prototype into the world\n  Pull a prototype from a ResourceX source and register it locally.\n  Once settled, the prototype can be used to create individuals or organizations.\n\n  Scenario: Settle a prototype\n    Given a valid ResourceX source exists (URL, path, or locator)\n    When settle is called with the source\n    Then the resource is ingested and its state is extracted\n    And the prototype is registered locally by its id\n    And the prototype is available for born, activate, and organizational use\n",
  skill:
    "Feature: skill — load full skill content\n  Load the complete skill instructions by ResourceX locator.\n  This is progressive disclosure layer 2 — on-demand knowledge injection.\n\n  Scenario: Load a skill\n    Given a procedure exists in the role with a locator\n    When skill is called with the locator\n    Then the full SKILL.md content is loaded via ResourceX\n    And the content is injected into the AI's context\n    And the AI can now follow the skill's detailed instructions\n",
  spec: "Feature: spec — define product specification\n  Define a behavior contract (BDD specification) for a product.\n  Specs describe the expected behavior of the product in Gherkin format.\n\n  Scenario: Define a product spec\n    Given a product exists in society\n    And a Gherkin source describing the behavior contract\n    When spec is called on the product with a spec id\n    Then the spec is stored as the product's information\n\n  Scenario: Parameters\n    Given the command is product.spec\n    Then product is required — the product's id\n    And content is required — Gherkin Feature source for the behavior contract (BDD specification)\n    And id is required — spec id (keywords joined by hyphens)\n\n  Scenario: Writing the spec Gherkin\n    Given the spec defines expected product behavior\n    Then the Feature title names the behavior or capability\n    And Scenarios describe Given-When-Then acceptance criteria\n    And the tone is precise — specifying exactly what the product should do\n",
  strategy:
    "Feature: strategy — define product strategy\n  Define the strategy for a product.\n  The strategy describes the product's direction, positioning, and competitive approach.\n\n  Scenario: Define product strategy\n    Given a product exists in society\n    And a Gherkin source describing the strategy\n    When strategy is called on the product with a strategy id\n    Then the strategy is stored as the product's information\n\n  Scenario: Parameters\n    Given the command is product.strategy\n    Then product is required — the product's id\n    And content is required — Gherkin Feature source for the strategy\n    And id is required — strategy id\n\n  Scenario: Writing the strategy Gherkin\n    Given the strategy defines the product's direction\n    Then the Feature title names the strategy\n    And Scenarios describe positioning, target audience, and competitive approach\n    And the tone is strategic — articulating where the product is headed and why\n",
  survey:
    "Feature: survey — world-level overview\n  List all entities in the world: individuals, organizations, positions.\n  Works without an active role — a stateless world query.\n\n  Scenario: Survey the world\n    When survey is called without arguments\n    Then all individuals, organizations, and positions are returned\n\n  Scenario: Filter by type\n    When survey is called with a type parameter\n    Then only entities of that type are returned\n    And valid types are individual, organization, position, past\n",
  teach:
    'Feature: teach — inject external principle\n  Directly inject a principle into an individual.\n  Unlike realize which consumes experience, teach requires no prior encounters.\n  Use teach to equip a role with a known, pre-existing principle.\n\n  Scenario: Teach a principle\n    Given an individual exists\n    When teach is called with the individual and principle content\n    Then a principle is created directly under the individual\n    And no experience or encounter is consumed\n    And if a principle with the same id already exists, it is replaced\n\n  Scenario: Parameters\n    Given the command is society.teach\n    Then individual is required — the individual\'s id\n    And content is required — Gherkin Feature describing the principle\n    And id is optional — kebab-case identifier for upsert (e.g. "always-validate-input")\n\n  Scenario: When to use teach vs realize\n    Given realize distills internal experience into a principle\n    And teach injects an external, pre-existing principle\n    When a role needs knowledge it has not learned through experience\n    Then use teach to inject the principle directly\n    When a role has gained experience and wants to codify it\n    Then use realize to distill it into a principle\n\n  Scenario: Writing the principle Gherkin\n    Given the principle is the same format as realize output\n    Then the Feature title states the principle as a general rule\n    And Scenarios describe different situations where this principle applies\n    And the tone is universal — no mention of specific projects, tasks, or people\n',
  todo: "Feature: todo — add a task to a plan\n  A task is a concrete, actionable unit of work.\n  Each task has Gherkin scenarios describing the steps and expected outcomes.\n\n  Scenario: Create a task\n    Given a focused plan exists\n    And a Gherkin source describing the task\n    When todo is called with the source\n    Then a new task node is created under the plan\n    And the task can be finished when completed\n\n  Scenario: Writing the task Gherkin\n    Given the task is a concrete, actionable unit of work\n    Then the Feature title names what will be done — a single deliverable\n    And Scenarios describe the steps and expected outcomes of the work\n    And the tone is actionable — clear enough that someone can start immediately\n",
  train:
    "Feature: train — external skill injection\n  A manager or external agent equips an individual with a procedure.\n  This is an act of teaching — someone else decides what the role should know.\n  Unlike master where the role grows by its own agency, train is done to the role from outside.\n\n  Scenario: Train a procedure\n    Given an individual exists\n    When train is called with the individual and procedure content\n    Then a procedure is created directly under the individual\n    And if a procedure with the same id already exists, it is replaced\n\n  Scenario: Parameters\n    Given the command is society.train\n    Then individual is required — the individual's id\n    And content is required — Gherkin Feature describing the procedure\n    And id is optional — kebab-case identifier for upsert (e.g. \"skill-creator\")\n\n  Scenario: When to use train vs master\n    Given both create procedures and both can work without consuming experience\n    When the role itself decides to acquire a skill — use master (self-growth)\n    And when an external agent equips the role — use train (external injection)\n    Then the difference is perspective — who initiates the learning\n    And master belongs to the role namespace (the role's own cognition)\n    And train belongs to the individual namespace (external management)\n\n  Scenario: Writing the procedure Gherkin\n    Given the procedure is a skill reference — same format as master output\n    Then the Feature title names the capability\n    And the description includes the locator for full skill loading\n    And Scenarios describe when and why to apply this skill\n",
  unadmin:
    "Feature: unadmin — revoke organization administrator\n  Revoke admin privileges from an individual within an organization.\n  The individual remains a member but loses management capabilities.\n\n  Scenario: Revoke admin\n    Given an individual is an admin of an organization\n    When unadmin is called with the organization and individual\n    Then the individual loses admin privileges\n    And the individual remains a member of the organization\n\n  Scenario: Parameters\n    Given the command is org.unadmin\n    Then org is required — the organization's id\n    And individual is required — the individual's id\n",
  unmaintain:
    "Feature: unmaintain — remove project maintainer\n  Remove maintainer role from an individual on a project.\n\n  Scenario: Remove a maintainer\n    Given an individual is a maintainer of a project\n    When unmaintain is called with the project and individual\n    Then the individual is no longer a maintainer of the project\n\n  Scenario: Parameters\n    Given the command is project.unmaintain\n    Then project is required — the project's id\n    And individual is required — the individual's id\n",
  use: 'Feature: use — act as the current role\n  Execute commands and load resources as the active role.\n  Use requires an active role — the role is the subject performing the action.\n  For operations before activating a role, use the direct tool instead.\n\n  Scenario: When to use "use" vs "direct"\n    Given a role is activated — I am someone\n    When I perform operations through use\n    Then the operation happens in the context of my role\n    And use is for role-level actions — acting in the world as myself\n\n  Scenario: Execute a RoleX command\n    Given the locator starts with `!`\n    When use is called with the locator and named args\n    Then the command is parsed as `namespace.method`\n    And dispatched to the corresponding RoleX API\n\n  Scenario: Load a ResourceX resource\n    Given the locator does not start with `!`\n    When use is called with the locator\n    Then the locator is passed to ResourceX for resolution\n    And the resource is loaded and returned\n',
  want: 'Feature: want — declare a goal\n  Declare a new goal for a role.\n  A goal describes a desired outcome with Gherkin scenarios as success criteria.\n\n  Scenario: Declare a goal\n    Given an active role exists\n    And a Gherkin source describing the desired outcome\n    When want is called with the source\n    Then a new goal node is created under the role\n    And the goal becomes the current focus\n    And subsequent plan and todo operations target this goal\n\n  Scenario: Writing the goal Gherkin\n    Given the goal describes a desired outcome — what success looks like\n    Then the Feature title names the outcome in concrete terms\n    And Scenarios define success criteria — each scenario is a testable condition\n    And the tone is aspirational but specific — "users can log in" not "improve auth"\n',
  wiki: "Feature: wiki — add a wiki entry to a project\n  Add a wiki entry to a project.\n  Wiki entries capture knowledge, documentation, and reference material for the project.\n\n  Scenario: Add a wiki entry\n    Given a project exists in society\n    And a Gherkin source describing the wiki entry\n    When wiki is called on the project with a wiki entry id\n    Then the wiki entry is stored as the project's information\n\n  Scenario: Parameters\n    Given the command is project.wiki\n    Then project is required — the project's id\n    And content is required — Gherkin Feature source for the wiki entry\n    And id is required — wiki entry id (keywords joined by hyphens)\n\n  Scenario: Writing the wiki Gherkin\n    Given the wiki entry captures project knowledge\n    Then the Feature title names the topic\n    And Scenarios describe key facts, decisions, or reference material\n    And the tone is informational — documenting what is known\n",
} as const;
